SELECT c.course_title, COALESCE(i.instructor_name, '') AS instructor_name
FROM courses c
LEFT JOIN instructors i ON c.instructor_names = i.instructor_id;

SELECT COUNT(DISTINCT user_id)
FROM user_courses
WHERE status = 'completed';

SELECT u.user_name, uc.user_rating, uc.user_review
FROM users u
INNER JOIN user_courses uc ON u.user_id = uc.user_id;

SELECT course_title, course_description
FROM courses
WHERE course_id = 1;
